package main

import (
	"fmt"
	"sync"
)

// Account represents a bank account
type Account struct {
	Balance int
}

// Deposit updates the balance of an account
func (a *Account) Deposit(amount int) {
	a.Balance += amount
}

// Withdraw updates the balance of an account
func (a *Account) Withdraw(amount int) error {
	if a.Balance < amount {
		return fmt.Errorf("insufficient funds")
	}
	a.Balance -= amount
	return nil
}

// Balance returns the current balance of an account
func (a *Account) Balance() int {
	return a.Balance
}

// CheckBalance checks the balance of an account and updates it if necessary
func CheckBalance(account *Account, amount int) error {
	if account.Balance < amount {
		return fmt.Errorf("insufficient funds")
	}
	account.Balance -= amount
	return nil
}

// UpdateBalance updates the balance of an account
func UpdateBalance(account *Account, amount int) {
	account.Balance += amount
}

// ProcessTransactions processes concurrent bank transactions
func ProcessTransactions(transactions []*Transaction, wg *sync.WaitGroup) {
	defer wg.Done()

	for _, transaction := range transactions {
		switch transaction.Type {
		case "deposit":
			err := CheckBalance(transaction.Account, transaction.Amount)
			if err != nil {
				fmt.Println("Error:", err)
			} else {
				UpdateBalance(transaction.Account, transaction.Amount)
			}
		case "withdraw":
			err := CheckBalance(transaction.Account, -transaction.Amount)
			if err != nil {
				fmt.Println("Error:", err)
			} else {
				UpdateBalance(transaction.Account, -transaction.Amount)
			}
		}
	}
}

// main function
func main() {
	var wg sync.WaitGroup

	accounts := map[string]*Account{
		"Alice": &Account{Balance: 1000},
		"Bob":   &Account{Balance: 2000},
	}

	transactions := []*Transaction{
		{"Alice", "deposit", 500},
		{"Bob", "withdraw", 100},
		{"Alice", "withdraw", 200},
	}

	for i := 0; i < len(transactions); i++ {
		wg.Add(1)
		go ProcessTransactions(transactions[i], &wg)
	}
	wg.Wait()

	fmt.Println("Alice's balance:", accounts["Alice"].Balance)
	fmt.Println("Bob's balance:", accounts["Bob"].Balance)
}